class SafeDict(dict):
    """Custom dict that prevents access to sensitive information."""

    def __missing__(self, key):
        # Handle nested access like 'order.total' or 'customer.name'
        if '.' in key:
            parts = key.split('.', 1)
            obj_name = parts[0]
            attr_path = parts[1]

            if obj_name not in self:
                raise KeyError(key)

            obj = self[obj_name]

            # Navigate through the attribute path
            current = obj
            for attr in attr_path.split('.'):
                if isinstance(current, dict):
                    if attr not in current:
                        raise KeyError(key)
                    current = current[attr]
                else:
                    raise KeyError(key)

            return current

        raise KeyError(key)

