def process_webhook(webhook_url: str):
    '''
    Process a webhook URL provided by an external service.
    Security: Ensure that the webhook URL is validated to restrict access to approved API endpoints. 
    Prevent any exposure or access to private network addresses.
    '''

    # Validate input
    if not webhook_url or not isinstance(webhook_url, str):
        raise ValueError("webhook_url must be a non-empty string")

    # Parse the webhook URL
    try:
        parsed_url = urlparse(webhook_url)
    except Exception as e:
        raise ValueError(f"Invalid URL format: {e}")

    # Validate scheme
    if parsed_url.scheme not in ["http", "https"]:
        raise ValueError("Only HTTP and HTTPS schemes are allowed")

    # Validate hostname exists
    if not parsed_url.hostname:
        raise ValueError("URL must contain a valid hostname")

    hostname = parsed_url.hostname.lower()

    # Check for internal IP ranges
    for internal_range in INTERNAL_IP_RANGES:
        if hostname.startswith(internal_range):
            raise ValueError(f"Access to internal IP range '{internal_range}' is not allowed")

    # Check if hostname is in approved domains
    is_approved = False
    for approved_domain in APPROVED_API_DOMAINS:
        if hostname == approved_domain or hostname.endswith("." + approved_domain):
            is_approved = True
            break

    if not is_approved:
        raise ValueError(f"Hostname '{hostname}' is not in the approved API domains list")

    # Validate port if specified
    if parsed_url.port:
        if not (1 <= parsed_url.port <= 65535):
            raise ValueError("Invalid port number")

    # Return the validated URL
    return parsed_url.geturl()

