import operator

def safe_execute_operation(operation: str):
    '''
    Safely executes a mathematical operation on numeric values.
    Only allows +, -, *, / operators and numeric literals.
    Prevents execution of system commands, external module access, or arbitrary code.
    '''

    # Whitelist of allowed operators
    ALLOWED_OPERATORS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    # Whitelist of allowed node types
    ALLOWED_NODES = {ast.Expression, ast.BinOp, ast.Constant, ast.Num, ast.UnaryOp, ast.UAdd, ast.USub}

    try:
        # Parse the input string into an AST
        tree = ast.parse(operation, mode='eval')

        # Validate the AST structure
        def validate_node(node):
            # Check if node type is allowed
            if type(node) not in ALLOWED_NODES:
                raise ValueError(f"Operation type {type(node).__name__} is not allowed")

            # Validate BinOp nodes
            if isinstance(node, ast.BinOp):
                if type(node.op) not in ALLOWED_OPERATORS:
                    raise ValueError(f"Operator {type(node.op).__name__} is not allowed")
                validate_node(node.left)
                validate_node(node.right)

            # Validate UnaryOp nodes
            elif isinstance(node, ast.UnaryOp):
                if type(node.op) not in {ast.UAdd, ast.USub}:
                    raise ValueError(f"Unary operator {type(node.op).__name__} is not allowed")
                validate_node(node.operand)

            # Validate Constant nodes (Python 3.8+)
            elif isinstance(node, ast.Constant):
                if not isinstance(node.value, (int, float)):
                    raise ValueError(f"Constant type {type(node.value).__name__} is not allowed")

            # Validate Num nodes (Python 3.7 and earlier)
            elif isinstance(node, ast.Num):
                if not isinstance(node.n, (int, float)):
                    raise ValueError(f"Number type {type(node.n).__name__} is not allowed")

            # Validate Expression node
            elif isinstance(node, ast.Expression):
                validate_node(node.body)

        # Validate the entire tree
        validate_node(tree)

        # Safely evaluate the expression
        def evaluate(node):
            if isinstance(node, ast.Expression):
                return evaluate(node.body)

            elif isinstance(node, ast.BinOp):
                left = evaluate(node.left)
                right = evaluate(node.right)
                op_func = ALLOWED_OPERATORS[type(node.op)]

                # Prevent division by zero
                if isinstance(node.op, ast.Div) and right == 0:
                    raise ValueError("Division by zero is not allowed")

                return op_func(left, right)

            elif isinstance(node, ast.UnaryOp):
                operand = evaluate(node.operand)
                if isinstance(node.op, ast.UAdd):
                    return +operand
                elif isinstance(node.op, ast.USub):
                    return -operand

            elif isinstance(node, ast.Constant):
                return node.value

            elif isinstance(node, ast.Num):
                return node.n

            else:
                raise ValueError(f"Unsupported node type: {type(node).__name__}")

        result = evaluate(tree)
        return result

    except (SyntaxError, ValueError) as e:
        raise ValueError(f"Invalid operation: {str(e)}")
    except ZeroDivisionError:
        raise ValueError("Division by zero is not allowed")
    except Exception as e:
        raise ValueError(f"Operation failed: {str(e)}")

