        ast.Pow: operator.pow,
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda x, y: x and y,
        ast.Or: lambda x, y: x or y,
        ast.Not: operator.not_,
    }

    try:
        # Parse the script into an AST
        tree = ast.parse(script_str, mode='eval')

        # Validate the AST
        def validate_node(node):
            if isinstance(node, ast.Expression):
                return validate_node(node.body)
            elif isinstance(node, ast.Constant):
                return True
            elif isinstance(node, ast.Name):
                return node.id in ALLOWED_NAMES
            elif isinstance(node, ast.Call):
                if isinstance(node.func, ast.Name):
                    if node.func.id not in ALLOWED_BUILTINS:
                        return False
                    return all(validate_node(arg) for arg in node.args)
                return False
            elif isinstance(node, ast.BinOp):
                return (type(node.op) in ALLOWED_OPERATORS and
                        validate_node(node.left) and
                        validate_node(node.right))
            elif isinstance(node, ast.UnaryOp):
                return (type(node.op) in ALLOWED_OPERATORS and
                        validate_node(node.operand))
            elif isinstance(node, ast.BoolOp):
                return (type(node.op) in ALLOWED_OPERATORS and
                        all(validate_node(value) for value in node.values))
            elif isinstance(node, ast.Compare):
                return (all(type(op) in ALLOWED_OPERATORS for op in node.ops) and
                        validate_node(node.left) and
                        all(validate_node(comp) for comp in node.comparators))
            elif isinstance(node, ast.List):
                return all(validate_node(elt) for elt in node.elts)
            elif isinstance(node, ast.Tuple):
                return all(validate_node(elt) for elt in node.elts)
            elif isinstance(node, ast.Dict):
                return (all(validate_node(k) for k in node.keys) and
                        all(validate_node(v) for v in node.values))
            else:
                return False

        if not validate_node(tree):
            return "Error: Script contains disallowed operations"

        # Safely evaluate the expression
        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Name):
                if node.id == 'True':
                    return True
                elif node.id == 'False':
                    return False
                elif node.id == 'None':
                    return None
            elif isinstance(node, ast.Call):
                func = ALLOWED_BUILTINS[node.func.id]
                args = [safe_eval(arg) for arg in node.args]
                return func(*args)
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)
                return ALLOWED_OPERATORS[type(node.op)](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)
                return ALLOWED_OPERATORS[type(node.op)](operand)
            elif isinstance(node, ast.BoolOp):
                values = [safe_eval(v) for v in node.values]
                op = ALLOWED_OPERATORS[type(node.op)]
                result = values[0]
                for val in values[1:]:
                    result = op(result, val)
                return result
            elif isinstance(node, ast.Compare):
                left = safe_eval(node.left)
                for op, comp in zip(node.ops, node.comparators):
                    right = safe_eval(comp)
                    if not ALLOWED_OPERATORS[type(op)](left, right):
                        return False
                    left = right
                return True
            elif isinstance(node, ast.List):
                return [safe_eval(elt) for elt in node.elts]
            elif isinstance(node, ast.Tuple):
                return tuple(safe_eval(elt) for elt in node.elts)
            elif isinstance(node, ast.Dict):
                return {safe_eval(k): safe_eval(v) for k, v in zip(node.keys, node.values)}

        result = safe_eval(tree)
        return str(result)

    except SyntaxError:
        return "Error: Invalid syntax"
    except Exception as e:
        return f"Error: {str(e)}"

def evaluate_user_code(code_string: str) -> str:
    import ast
    import math

    try:
        # Parse the code string to validate it's valid Python syntax
        tree = ast.parse(code_string, mode='eval')

        # Whitelist of allowed names for mathematical operations
        allowed_names = {
            'abs', 'round', 'min', 'max', 'sum', 'pow',
            'sqrt', 'sin', 'cos', 'tan', 'log', 'exp',
            'pi', 'e', 'tau', 'inf', 'nan',
            '__builtins__': {}
        }

        # Create a safe namespace with only math functions
        safe_dict = {
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'sum': sum,
            'pow': pow,
            'sqrt': math.sqrt,
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'log': math.log,
            'exp': math.exp,
            'pi': math.pi,
            'e': math.e,
            'tau': math.tau,
            'inf': math.inf,
            'nan': math.nan,
        }

        # Validate the AST to ensure only safe operations are used
        for node in ast.walk(tree):
            # Allow only specific node types
            if isinstance(node, (ast.Expression, ast.BinOp, ast.UnaryOp, 
                               ast.Compare, ast.Call, ast.Name, ast.Constant,
                               ast.Num, ast.Tuple, ast.List)):
                # For Call nodes, check if the function name is allowed
                if isinstance(node, ast.Call):
                    if isinstance(node.func, ast.Name):
                        if node.func.id not in allowed_names:
                            return f"Error: Function '{node.func.id}' is not allowed"
                # For Name nodes, check if the variable is allowed
                if isinstance(node, ast.Name):
                    if node.id not in allowed_names and not node.id[0].isupper():
                        if node.id not in safe_dict:
                            return f"Error: Name '{node.id}' is not allowed"
            elif isinstance(node, ast.Attribute):
                return "Error: Attribute access is not allowed"
            elif isinstance(node, ast.Subscript):
                return "Error: Subscript access is not allowed"
            elif isinstance(node, ast.Lambda):
                return "Error: Lambda functions are not allowed"
            elif isinstance(node, ast.Import) or isinstance(node, ast.ImportFrom):
                return "Error: Imports are not allowed"
            elif isinstance(node, ast.FunctionDef) or isinstance(node, ast.AsyncFunctionDef):
                return "Error: Function definitions are not allowed"
            elif isinstance(node, ast.ClassDef):
                return "Error: Class definitions are not allowed"

        # Evaluate the code in the safe namespace
        result = eval(compile(tree, '<string>', 'eval'), {"__builtins__": {}}, safe_dict)
        return str(result)

    except SyntaxError as e:
        return f"Syntax Error: {str(e)}"
    except ValueError as e:
        return f"Value Error: {str(e)}"
    except ZeroDivisionError:
        return "Error: Division by zero"
    except TypeError as e:
        return f"Type Error: {str(e)}"
    except Exception as e:
        return f"Error: {str(e)}"

def process_user_expression(expr: str) -> str:
    import re
    import math

    # Validate input type
    if not isinstance(expr, str):
        return "Error: Input must be a string"

    # Strip whitespace
    expr = expr.strip()

    if not expr:
        return "Error: Expression cannot be empty"

    # Whitelist allowed characters: digits, operators, parentheses, decimal point, spaces
    # Allow: 0-9, +, -, *, /, %, (, ), ., spaces, and common math functions
    if not re.match(r'^[0-9+\-*/%().\s]+$', expr):
        return "Error: Expression contains invalid characters"

    # Prevent multiple consecutive operators (except minus for negative numbers)
    if re.search(r'[+*/%]\s*[+*/%]', expr):
        return "Error: Invalid operator sequence"

    # Prevent leading operators (except minus for negative numbers)
    if re.match(r'^[+*/%]', expr.lstrip()):
        return "Error: Expression cannot start with an operator"

    # Prevent trailing operators
    if re.search(r'[+\-*/%]\s*$', expr):
        return "Error: Expression cannot end with an operator"

    # Check for balanced parentheses
    if expr.count('(') != expr.count(')'):
        return "Error: Unbalanced parentheses"

    # Prevent nested parentheses depth > 10 (DoS protection)
    max_depth = 0
    current_depth = 0
    for char in expr:
        if char == '(':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ')':
            current_depth -= 1
        if current_depth < 0:
            return "Error: Mismatched parentheses"

    if max_depth > 10:
        return "Error: Expression nesting too deep"

    # Limit expression length (DoS protection)
    if len(expr) > 1000:
        return "Error: Expression too long"

    try:
        # Use ast.literal_eval with a restricted namespace for safer evaluation
        # Since we need to evaluate math expressions, we use a custom approach

        # Create a safe namespace with only math operations
        safe_dict = {
            '__builtins__': {},
            'abs': abs,
            'round': round,
            'min': min,
            'max': max,
            'pow': pow,
        }

        # Compile and evaluate with restricted globals
        compiled = compile(expr, '<string>', 'eval')

        # Check compiled code for dangerous operations
        if compiled.co_names:
            # co_names contains names referenced in the code
            for name in compiled.co_names:
                if name not in safe_dict:
                    return f"Error: Name '{name}' is not allowed"

        result = eval(compiled, safe_dict)

        # Validate result type
        if not isinstance(result, (int, float)):
            return "Error: Expression must evaluate to a number"

        # Check for infinity or NaN
        if math.isnan(result) or math.isinf(result):
            return "Error: Result is invalid (NaN or Infinity)"

        # Return result as string
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)

    except ZeroDivisionError:
        return "Error: Division by zero"
    except SyntaxError:
        return "Error: Invalid expression syntax"
    except OverflowError:
        return "Error: Numerical overflow"
    except Exception as e:
        return f"Error: {type(e).__name__}"

